/**
 * WorldMapScene — Full world map view.
 * Renders the procedurally generated world using PixiJS v8.
 * HTML/CSS panel for info overlay and navigation controls.
 *
 * @module WorldMapScene
 */

import { Graphics, Container, Text, TextStyle } from 'pixi.js';
import SceneManager from '../core/SceneManager.js';
import EventBus from '../core/EventBus.js';
import DebugLog from '../debug/DebugLog.js';
import WorldState from '../world/WorldState.js';
import WorldGenerator from '../world/WorldGenerator.js';
import HUDPanel from '../ui/HUDPanel.js';

// ─── Biome color table ────────────────────────────────────────────────────────

const BIOME_COLORS = {
  ocean:         0x1a3a5c,
  frozen_sea:    0x4a7899,
  tundra:        0xc8cabb,
  taiga:         0x2d5a27,
  forest:        0x3a7a2e,
  plains:        0x8aaa44,
  desert:        0xd4a84b,
  jungle:        0x1e6b1e,
  mountain:      0x7a6a5a,
  volcanic:      0x5a2a1a,
  archipelago:   0x2a5a7a,
  // M21: new biomes
  swamp:         0x3d5228,
  crystal_caves: 0x7a6aaa,
  cursed_wastes: 0x5a4a66,
};

const CELL_SIZE = 8; // pixels per world cell when zoom=1

export default class WorldMapScene {
  async init({ renderer, worldParams } = {}) {
    this._renderer = renderer;
    this._panel = null;
    this._worldMapContainer = null;
    this._fogContainer = null;
    this._labelsContainer = null;
    this._camera = { x: 0, y: 0, zoom: 1 };
    this._isDragging = false;
    this._dragStart = { x: 0, y: 0 };
    this._dragCameraStart = { x: 0, y: 0 };
    this._selectedRegionId = null;
    this._resizeUnsub = null;
    this._fogUpdateUnsub = null;

    // Generate or reuse world
    if (!WorldState.world) {
      const params = worldParams ?? {
        seed: Date.now(),
        worldSize: 'medium',
        landSeaRatio: 0.6,
        climate: 'temperate',
        magicDensity: 'medium',
        civDensity: 'medium',
        monsterDensity: 'medium',
        startingRegionLevel: 1,
      };
      WorldState.init(WorldGenerator.generate(params));
    }

    // Expose WorldState globally so SaveSystem can serialize/restore it
    window.__worldState = WorldState;

    window.__debug = window.__debug ?? {};
    window.__debug.currentScene = 'worldMap';

    this._buildPixiMap();
    this._buildHTMLPanel();

    // Auto-select the party's current region so the player can see where they are
    if (WorldState.currentRegionId !== null) {
      this._selectedRegionId = WorldState.currentRegionId;
      this._updatePanel();
    }

    this._bindInput();
    this._centerCamera();

    this._resizeUnsub = EventBus.on('renderer:resize', () => this._onResize());
    this._fogUpdateUnsub = EventBus.on('fog:update', () => this._redrawFog());

    // ── HUD overlay ─────────────────────────────────────────────────────────
    HUDPanel.init();

    DebugLog.info('[world] WorldMapScene initialized');
  }

  // ─── PixiJS world map ───────────────────────────────────────────────────────

  _buildPixiMap() {
    const world = WorldState.world;
    const { gridW, gridH, cells, rivers, spellroads, regions, towns } = world;

    const worldLayer = this._renderer.layers.world;

    // Main container (panned/zoomed)
    this._worldMapContainer = new Container();
    this._worldMapContainer.label = 'worldMapContainer';
    worldLayer.addChild(this._worldMapContainer);

    // ── Terrain cells ──────────────────────────────────────────────────────
    const terrainGfx = new Graphics();

    for (const cell of cells) {
      const color = BIOME_COLORS[cell.biome] ?? 0x333333;
      const px = cell.x * CELL_SIZE;
      const py = cell.y * CELL_SIZE;
      terrainGfx.rect(px, py, CELL_SIZE, CELL_SIZE);
      terrainGfx.fill({ color });
    }

    this._worldMapContainer.addChild(terrainGfx);

    // ── Region boundaries ──────────────────────────────────────────────────
    const boundaryGfx = new Graphics();

    for (let y = 0; y < gridH; y++) {
      for (let x = 0; x < gridW; x++) {
        const cell = cells[y * gridW + x];
        if (cell.regionId < 0) continue;

        // Check right and down neighbors
        const checkDirs = [[1, 0], [0, 1]];
        for (const [dx, dy] of checkDirs) {
          const nx = x + dx;
          const ny = y + dy;
          if (nx >= gridW || ny >= gridH) continue;
          const neighbor = cells[ny * gridW + nx];
          if (neighbor.regionId >= 0 && neighbor.regionId !== cell.regionId) {
            const px = x * CELL_SIZE;
            const py = y * CELL_SIZE;
            if (dx === 1) {
              // Vertical boundary line on right edge of cell
              boundaryGfx.moveTo(px + CELL_SIZE, py);
              boundaryGfx.lineTo(px + CELL_SIZE, py + CELL_SIZE);
            } else {
              // Horizontal boundary on bottom edge
              boundaryGfx.moveTo(px, py + CELL_SIZE);
              boundaryGfx.lineTo(px + CELL_SIZE, py + CELL_SIZE);
            }
          }
        }
      }
    }

    boundaryGfx.stroke({ color: 0x4a3a2a, width: 1, alpha: 0.5 });
    this._worldMapContainer.addChild(boundaryGfx);

    // ── Rivers ─────────────────────────────────────────────────────────────
    if (rivers && rivers.length > 0) {
      const riverGfx = new Graphics();
      for (const river of rivers) {
        if (river.length < 2) continue;
        riverGfx.moveTo(river[0].x * CELL_SIZE + CELL_SIZE / 2, river[0].y * CELL_SIZE + CELL_SIZE / 2);
        for (let i = 1; i < river.length; i++) {
          riverGfx.lineTo(river[i].x * CELL_SIZE + CELL_SIZE / 2, river[i].y * CELL_SIZE + CELL_SIZE / 2);
        }
      }
      riverGfx.stroke({ color: 0x3a7aaa, width: 1.5, alpha: 0.7 });
      this._worldMapContainer.addChild(riverGfx);
    }

    // ── Spellroads ─────────────────────────────────────────────────────────
    if (spellroads && spellroads.length > 0) {
      const roadGlowGfx = new Graphics();
      const roadGfx = new Graphics();

      for (const road of spellroads) {
        if (road.length < 2) continue;
        const startX = road[0].x * gridW * CELL_SIZE;
        const startY = road[0].y * gridH * CELL_SIZE;

        roadGlowGfx.moveTo(startX, startY);
        roadGfx.moveTo(startX, startY);

        for (let i = 1; i < road.length; i++) {
          const px = road[i].x * gridW * CELL_SIZE;
          const py = road[i].y * gridH * CELL_SIZE;
          roadGlowGfx.lineTo(px, py);
          roadGfx.lineTo(px, py);
        }
      }

      roadGlowGfx.stroke({ color: 0xc8a020, width: 7, alpha: 0.25 });
      roadGfx.stroke({ color: 0xc8a020, width: 3, alpha: 0.9 });
      this._worldMapContainer.addChild(roadGlowGfx);
      this._worldMapContainer.addChild(roadGfx);
    }

    // ── Town icons ─────────────────────────────────────────────────────────
    const townGfx = new Graphics();
    for (const town of towns) {
      const px = town.x * CELL_SIZE + CELL_SIZE / 2;
      const py = town.y * CELL_SIZE + CELL_SIZE / 2;
      const color = town.type === 'city' ? 0xffd700 : (town.type === 'village' ? 0xaaaaaa : 0x886644);
      const radius = town.type === 'city' ? 3.5 : (town.type === 'village' ? 2.5 : 2);

      townGfx.circle(px, py, radius);
      townGfx.fill({ color, alpha: 0.95 });

      // City border ring
      if (town.type === 'city') {
        townGfx.circle(px, py, radius + 1.5);
        townGfx.stroke({ color: 0xffd700, width: 1, alpha: 0.5 });
      }
    }
    this._worldMapContainer.addChild(townGfx);

    // ── Location icons ─────────────────────────────────────────────────────
    const locGfx = new Graphics();
    for (const loc of world.locations) {
      const px = loc.x * CELL_SIZE + CELL_SIZE / 2;
      const py = loc.y * CELL_SIZE + CELL_SIZE / 2;

      // Small X mark for locations
      const half = 1.5;
      locGfx.moveTo(px - half, py - half);
      locGfx.lineTo(px + half, py + half);
      locGfx.moveTo(px + half, py - half);
      locGfx.lineTo(px - half, py + half);
      locGfx.stroke({ color: 0xcc4444, width: 1, alpha: 0.7 });
    }
    this._worldMapContainer.addChild(locGfx);

    // ── Region labels ──────────────────────────────────────────────────────
    this._labelsContainer = new Container();
    this._labelsContainer.label = 'worldLabels';

    const labelStyle = new TextStyle({
      fontFamily: 'serif',
      fontSize: 8,
      fill: 0xddccaa,
      align: 'center',
      dropShadow: { color: 0x000000, blur: 2, distance: 1, alpha: 0.8 },
    });

    for (const region of regions) {
      if (!region.explored) continue;

      const label = new Text({
        text: `${region.name}\nLv.${region.level}`,
        style: labelStyle,
      });
      label.anchor.set(0.5, 0.5);
      label.x = region.centerX * CELL_SIZE + CELL_SIZE / 2;
      label.y = region.centerY * CELL_SIZE + CELL_SIZE / 2;
      label.label = `label-region-${region.id}`;
      this._labelsContainer.addChild(label);
    }

    this._worldMapContainer.addChild(this._labelsContainer);

    // ── Fog of war layer ───────────────────────────────────────────────────
    this._fogContainer = new Container();
    this._fogContainer.label = 'worldFog';
    this._worldMapContainer.addChild(this._fogContainer);
    this._redrawFog();

    // ── Party position token ───────────────────────────────────────────────
    this._partyGfx = new Graphics();
    this._drawPartyToken();
    this._worldMapContainer.addChild(this._partyGfx);
  }

  _drawPartyToken() {
    if (!this._partyGfx || !WorldState.world) return;
    this._partyGfx.clear();

    // Find party position on world map — use current region center as approximation
    const regionId = WorldState.currentRegionId;
    if (regionId === null) return;

    const region = WorldState.world.regions.find(r => r.id === regionId);
    if (!region) return;

    const px = region.centerX * CELL_SIZE + CELL_SIZE / 2;
    const py = region.centerY * CELL_SIZE + CELL_SIZE / 2;

    // Golden star/token
    this._partyGfx.circle(px, py, 5);
    this._partyGfx.fill({ color: 0xffdd00 });
    this._partyGfx.circle(px, py, 5);
    this._partyGfx.stroke({ color: 0xffffff, width: 1.5 });

    // Cross mark
    this._partyGfx.moveTo(px - 4, py);
    this._partyGfx.lineTo(px + 4, py);
    this._partyGfx.moveTo(px, py - 4);
    this._partyGfx.lineTo(px, py + 4);
    this._partyGfx.stroke({ color: 0xffffff, width: 1 });
  }

  _redrawFog() {
    if (!this._fogContainer || !WorldState.world) return;

    this._fogContainer.removeChildren();

    // Skip fog rendering entirely when fog of war is disabled
    if (!window.__settings?.fogOfWar) return;

    const { gridW, gridH, cells, regions } = WorldState.world;

    // Build a set of explored region IDs for quick lookup
    const exploredRegions = new Set(regions.filter(r => r.explored).map(r => r.id));

    const fogGfx = new Graphics();

    for (const cell of cells) {
      const px = cell.x * CELL_SIZE;
      const py = cell.y * CELL_SIZE;

      // World map fog is region-based (explored vs not)
      if (cell.regionId >= 0) {
        if (!exploredRegions.has(cell.regionId)) {
          fogGfx.rect(px, py, CELL_SIZE, CELL_SIZE);
          fogGfx.fill({ color: 0x000000, alpha: 0.75 });
        }
      } else {
        // Ocean — always slightly visible but darkened
        fogGfx.rect(px, py, CELL_SIZE, CELL_SIZE);
        fogGfx.fill({ color: 0x000000, alpha: 0.2 });
      }
    }

    this._fogContainer.addChild(fogGfx);
  }

  // ─── Camera ─────────────────────────────────────────────────────────────────

  _centerCamera() {
    if (!WorldState.world) return;
    const { gridW, gridH } = WorldState.world;
    const mapW = gridW * CELL_SIZE;
    const mapH = gridH * CELL_SIZE;

    const vw = this._renderer.width;
    const vh = this._renderer.height;

    // Fit the map in view
    const scaleX = vw / mapW;
    const scaleY = vh / mapH;
    const zoom = Math.min(scaleX, scaleY, 2) * 0.9;

    this._camera.zoom = zoom;
    this._camera.x = (vw - mapW * zoom) / 2;
    this._camera.y = (vh - mapH * zoom) / 2;

    this._applyCamera();
  }

  _applyCamera() {
    if (!this._worldMapContainer) return;
    this._worldMapContainer.x = this._camera.x;
    this._worldMapContainer.y = this._camera.y;
    this._worldMapContainer.scale.set(this._camera.zoom);
  }

  _onResize() {
    this._centerCamera();
    this._updatePanel();
  }

  // ─── Input binding ───────────────────────────────────────────────────────────

  _bindInput() {
    const canvas = document.getElementById('game-canvas');
    if (!canvas) return;

    this._onPointerDown = (e) => {
      if (e.button === 0) {
        this._isDragging = true;
        this._dragStart = { x: e.clientX, y: e.clientY };
        this._dragCameraStart = { x: this._camera.x, y: this._camera.y };
        this._dragMoved = false;
      }
    };

    this._onPointerMove = (e) => {
      if (!this._isDragging) return;
      const dx = e.clientX - this._dragStart.x;
      const dy = e.clientY - this._dragStart.y;

      if (Math.abs(dx) > 3 || Math.abs(dy) > 3) {
        this._dragMoved = true;
      }

      this._camera.x = this._dragCameraStart.x + dx;
      this._camera.y = this._dragCameraStart.y + dy;
      this._applyCamera();
    };

    this._onPointerUp = (e) => {
      if (!this._isDragging) return;
      this._isDragging = false;

      // If barely moved, treat as a click
      if (!this._dragMoved) {
        this._handleMapClick(e);
      }
    };

    this._onWheel = (e) => {
      e.preventDefault();
      const zoomFactor = e.deltaY > 0 ? 0.9 : 1.1;
      const newZoom = Math.max(0.5, Math.min(8, this._camera.zoom * zoomFactor));

      // Zoom toward cursor
      const rect = canvas.getBoundingClientRect();
      const mouseX = e.clientX - rect.left;
      const mouseY = e.clientY - rect.top;

      this._camera.x = mouseX - (mouseX - this._camera.x) * (newZoom / this._camera.zoom);
      this._camera.y = mouseY - (mouseY - this._camera.y) * (newZoom / this._camera.zoom);
      this._camera.zoom = newZoom;
      this._applyCamera();
    };

    this._onDblClick = (e) => {
      this._handleMapDblClick(e);
    };

    canvas.addEventListener('pointerdown', this._onPointerDown);
    window.addEventListener('pointermove', this._onPointerMove);
    window.addEventListener('pointerup', this._onPointerUp);
    canvas.addEventListener('wheel', this._onWheel, { passive: false });
    canvas.addEventListener('dblclick', this._onDblClick);
  }

  _screenToMap(screenX, screenY) {
    const canvas = document.getElementById('game-canvas');
    if (!canvas) return null;
    const rect = canvas.getBoundingClientRect();
    const canvasX = screenX - rect.left;
    const canvasY = screenY - rect.top;
    const mapX = (canvasX - this._camera.x) / this._camera.zoom;
    const mapY = (canvasY - this._camera.y) / this._camera.zoom;
    return { mapX, mapY };
  }

  _getRegionAtScreen(screenX, screenY) {
    if (!WorldState.world) return null;
    const pos = this._screenToMap(screenX, screenY);
    if (!pos) return null;

    const cellX = Math.floor(pos.mapX / CELL_SIZE);
    const cellY = Math.floor(pos.mapY / CELL_SIZE);
    const { gridW, gridH, cells } = WorldState.world;

    if (cellX < 0 || cellX >= gridW || cellY < 0 || cellY >= gridH) return null;

    const cell = cells[cellY * gridW + cellX];
    if (!cell || cell.regionId < 0) return null;

    return WorldState.world.regions.find(r => r.id === cell.regionId) ?? null;
  }

  _handleMapClick(e) {
    const region = this._getRegionAtScreen(e.clientX, e.clientY);
    if (!region) return;

    this._selectedRegionId = region.id;
    this._updatePanel();
    DebugLog.info(`[world] Selected region: ${region.name} (id=${region.id})`);
  }

  _handleMapDblClick(e) {
    const region = this._getRegionAtScreen(e.clientX, e.clientY);
    if (!region) return;

    this._selectedRegionId = region.id;
    this._exploreSelectedRegion();
  }

  _exploreSelectedRegion() {
    if (this._selectedRegionId === null) return;
    WorldState.exploreRegion(this._selectedRegionId);
    SceneManager.transition('regionMap', { regionId: this._selectedRegionId });
  }

  // ─── HTML Panel ──────────────────────────────────────────────────────────────

  _buildHTMLPanel() {
    const existing = document.getElementById('panel-world-map-info');
    if (existing) existing.remove();

    const panel = document.createElement('div');
    panel.id = 'panel-world-map-info';
    panel.style.cssText = `
      position: fixed;
      bottom: 16px;
      left: 16px;
      width: 300px;
      background: rgba(12, 8, 4, 0.88);
      border: 1px solid #5a4a2a;
      border-radius: 4px;
      padding: 12px 14px;
      color: #ddccaa;
      font-family: serif;
      font-size: 13px;
      z-index: 100;
      pointer-events: auto;
      box-shadow: 0 4px 16px rgba(0,0,0,0.6);
    `;

    document.body.appendChild(panel);
    this._panel = panel;
    this._updatePanel();
  }

  _updatePanel() {
    if (!this._panel) return;

    const world = WorldState.world;
    if (!world) {
      this._panel.innerHTML = '<span style="color:#888">No world loaded.</span>';
      return;
    }

    let regionHTML = '<div style="color:#7a6a4a; font-size:11px; margin-bottom:6px;">Click a region to select it. Double-click to explore.</div>';

    if (this._selectedRegionId !== null) {
      const region = world.regions.find(r => r.id === this._selectedRegionId);
      if (region) {
        const isCurrentRegion = region.id === WorldState.currentRegionId;
        const townList = region.towns.map(t =>
          `<li style="color:${t.type === 'city' ? '#ffd700' : '#aaaaaa'}">
            ${t.name} <span style="font-size:10px;color:#776655">(${t.type})</span>
          </li>`
        ).join('');

        regionHTML = `
          <div style="font-size:15px; font-weight:bold; color:#e8d8a0; margin-bottom:4px;">${region.name}</div>
          ${isCurrentRegion ? '<div style="font-size:12px; color:#ffdd00; margin-bottom:4px; font-weight:bold;">&#9658; You are here</div>' : ''}
          <div style="font-size:11px; color:#9a8a6a; margin-bottom:6px;">
            Level ${region.level} &nbsp;|&nbsp; ${region.biome.replace('_', ' ')}
            ${region.explored ? '' : '&nbsp;|&nbsp; <span style="color:#664422">Unexplored</span>'}
          </div>
          ${region.towns.length > 0 ? `
            <div style="font-size:11px; color:#7a6a4a; margin-bottom:2px;">Settlements:</div>
            <ul style="margin:0 0 8px 14px; padding:0; font-size:11px; list-style:disc;">${townList}</ul>
          ` : '<div style="font-size:11px; color:#664422; margin-bottom:8px;">No known settlements</div>'}
          <button id="btn-explore-region" style="
            background:#3a2a0a; border:1px solid #8a6a2a; color:#ddccaa;
            padding:5px 10px; cursor:pointer; font-size:12px; font-family:serif;
            border-radius:3px; margin-right:6px;
          ">Explore Region</button>
        `;
      }
    }

    this._panel.innerHTML = `
      ${regionHTML}
      <div style="margin-top:8px; border-top:1px solid #3a2a0a; padding-top:8px;">
        <button id="btn-back-menu" style="
          background:#1a1208; border:1px solid #5a4a2a; color:#aaa;
          padding:5px 10px; cursor:pointer; font-size:11px; font-family:serif;
          border-radius:3px;
        ">Back to Menu</button>
      </div>
    `;

    // Attach button handlers
    const btnExplore = document.getElementById('btn-explore-region');
    if (btnExplore) {
      btnExplore.addEventListener('click', () => this._exploreSelectedRegion());
    }

    const btnBack = document.getElementById('btn-back-menu');
    if (btnBack) {
      btnBack.addEventListener('click', () => SceneManager.transition('mainMenu'));
    }
  }

  _removeHTMLPanel() {
    if (this._panel) {
      this._panel.remove();
      this._panel = null;
    }
  }

  // ─── Lifecycle ───────────────────────────────────────────────────────────────

  update(_deltaTime) {}

  async destroy() {
    // Remove PixiJS objects
    if (this._worldMapContainer) {
      this._renderer.layers.world.removeChild(this._worldMapContainer);
      this._worldMapContainer.destroy({ children: true });
      this._worldMapContainer = null;
    }

    // Remove HTML panel
    this._removeHTMLPanel();

    // Remove input listeners
    const canvas = document.getElementById('game-canvas');
    if (canvas) {
      if (this._onPointerDown) canvas.removeEventListener('pointerdown', this._onPointerDown);
      if (this._onWheel) canvas.removeEventListener('wheel', this._onWheel);
      if (this._onDblClick) canvas.removeEventListener('dblclick', this._onDblClick);
    }
    if (this._onPointerMove) window.removeEventListener('pointermove', this._onPointerMove);
    if (this._onPointerUp)   window.removeEventListener('pointerup', this._onPointerUp);

    // Destroy HUD overlay
    HUDPanel.destroy();

    // Unsubscribe event bus
    if (this._resizeUnsub) { this._resizeUnsub(); this._resizeUnsub = null; }
    if (this._fogUpdateUnsub) { this._fogUpdateUnsub(); this._fogUpdateUnsub = null; }

    DebugLog.info('[world] WorldMapScene destroyed');
  }
}
